- (void)gestureDetected:(UIGestureRecognizer *)sender {
    for (UICollectionViewCell *cell in self.collectionView.visibleCells) {
        if ([cell isKindOfClass:WBVappCollectionViewCell.class]) {//判断手势是否在vappCell上
            WBVappCollectionViewCell *vappCell = (WBVappCollectionViewCell *)cell;
            if (CGRectContainsPoint(vappCell.vappIconImageView.bounds, [sender locationInView:vappCell.vappIconImageView])) {//手势要点击到appIcon
                if ([sender isKindOfClass:UITapGestureRecognizer.class]) {//单击启动
                    if (!vappCell.vapp.isDownload) {
                        PostNotificationOnMainThread(WBGetVAppNotification, vappCell.vapp);
                    } else {
                        [self onPressVApp:vappCell.vapp isFromVappNotification:false];
                    }
                } else {//长按
                    UILongPressGestureRecognizer *longpress = (UILongPressGestureRecognizer *)sender;
                    if (longpress.state == UIGestureRecognizerStateBegan) {
                        [self onLongPressVAppCell:vappCell];
                    }
                }
                break;
            }
        } else {//判断手势是否在加号
            if (CGRectContainsPoint(cell.contentView.bounds, [sender locationInView:cell])) {
                if ([sender isKindOfClass:UITapGestureRecognizer.class]) {//切到发现（添加）界面
                    if (self.tabBarController.childViewControllers.count == 4) {
                        self.tabBarController.selectedIndex = 2;
                    } else {
                        self.tabBarController.selectedIndex = 1;
                    }
                }
                break;
            }
        }
    }
}

- (BOOL)gestureRecognizer:(UIGestureRecognizer *)gestureRecognizer shouldReceiveTouch:(UITouch *)touch {
    UIView *touchView = touch.view;
    while (touchView) {
        if ([touchView isKindOfClass:[WBHomeVappFeatureView class]]) {
            return NO;
        }
        touchView = touchView.superview;
    }
    return YES;
}

- (BOOL)gestureRecognizer:(UIGestureRecognizer *)gestureRecognizer shouldRecognizeSimultaneouslyWithGestureRecognizer:(UIGestureRecognizer *)otherGestureRecognizer {
    UIView *gestureView = gestureRecognizer.view;
    UIView *otherGestureView = otherGestureRecognizer.view;

    BOOL isGestureViewInFeature = NO;
    BOOL isOtherGestureViewInFeature = NO;

    // 检查第一个手势视图是否在 Feature 视图中
    UIView *superviewIterator = gestureView;
    while (superviewIterator) {
        if ([superviewIterator isKindOfClass:[WBHomeVappFeatureView class]]) {
            isGestureViewInFeature = YES;
            break;
        }
        superviewIterator = superviewIterator.superview;
    }

    // 检查第二个手势视图是否在 Feature 视图中
    superviewIterator = otherGestureView;
    while (superviewIterator) {
        if ([superviewIterator isKindOfClass:[WBHomeVappFeatureView class]]) {
            isOtherGestureViewInFeature = YES;
            break;
        }
        superviewIterator = superviewIterator.superview;
    }

    if (isGestureViewInFeature || isOtherGestureViewInFeature) {
        return YES;
    }
    return NO;
}

